            {
              "name": "dbtest"
            }
          ],
          "service1": [
            {
              "name": "test"
            }
          ]
        },
        "program": [
          {
            "op": "unsubscribe",
            "name": "dbtest",
            "args": [
              "a",
              "b",
              "c"
            ]
          },
          {
            "op": "unsubscribe",
            "name": "test",
            "args": [
              "a",
              "b",
              "c"
